pragma solidity ^0.8.0;

import "@openzeppelin/contracts/security/ReentrancyGuard.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

contract DaoFactory is ReentrancyGuard, Ownable {
    struct Dao {
        bool isCreated; // Combined state for isCreated and isInCreation
    }

    mapping(address => Dao) public daos;
    address public identityAddress;

    event DAOCreated(address indexed daoAddress);

    modifier onlyDuringCreation(address _daoAddress) {
        require(!daos[_daoAddress].isCreated, "DAO is not in creation phase");
        _;
    }

    modifier onlyIfNotCreated(address _daoAddress) {
        require(!daos[_daoAddress].isCreated, "DAO already created");
        _;
    }

    constructor() {
        identityAddress = msg.sender;
    }

    function createDao() external onlyIfNotCreated(msg.sender) returns (address) {
        address newDao = address(new DaoImplementation(msg.sender));
        daos[newDao] = Dao({isCreated: false});
        emit DAOCreated(newDao);
        return newDao;
    }

    function getDaoAddress(address _creator) external view returns (address) {
        return address(daos[_creator]);
    }

    function addAdapters(address[] calldata _adapterAddresses) external onlyDuringCreation(msg.sender) {
        DaoImplementation(msg.sender).addAdapters(_adapterAddresses);
    }

    function configureExtension(bytes calldata _configData) external onlyDuringCreation(msg.sender) {
        DaoImplementation(msg.sender).configureExtension(_configData);
    }

    function updateAdapter(address _oldAdapter, address _newAdapter) external onlyDuringCreation(msg.sender) {
        DaoImplementation(msg.sender).updateAdapter(_oldAdapter, _newAdapter);
    }

    function finalizeDao() external onlyDuringCreation(msg.sender) {
        daos[msg.sender].isCreated = true;
        // Additional logic to finalize DAO
    }

    receive() external payable nonReentrant {}

    function isDaoCreated(address _daoAddress) external view returns (bool) {
        return daos[_daoAddress].isCreated;
    }
}

